vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec3 orig=texture(sampler_main,vUv);
vec3 nex=texture(sampler_main,vec2(vUv.x+0.001,vUv.y));

if(abs(orig.x+orig.y+orig.z-nex.x-nex.y-nex.z)>0.1)
{ret=GetBlur2(vUv);}
else{ret=GetBlur3(vUv);};

ret += .66*GetBlur2(vUv);

ret *= 1.75;
ret = lum(ret);
ret = mix(.75*ret,ret*(GetBlur3(vUv)-GetBlur1(vUv)),(0.5*rand_preset+0.5*_qa.xyz)*ret);
ret *= ret; //darken
//ret *= ret;
